<script>
export default {
  name: "Accesories",
  data() {
    return {
      list: ['#a_earphones','#a_earring1','#a_earring2','#a_earring3','#g_none']
    }
  },

  methods: {
    picker(option = false){
      this.hide_all();
      option
        ? document.querySelector(option).classList.add('show')
        : document.querySelector(this.random_option()).classList.add('show');
    },
    random_option(){
      var chosenAccesories = Math.floor(Math.random() * this.list.length);
      return this.list[chosenAccesories];
    },
    hide_all(){
      for (let i = 0; i < this.list.length; i++){
        document.querySelector(this.list[i]).classList.remove('show');
      }
    }
  },

  created() {
    this.$root.$refs.Accesories = this;
  }
}
</script>
